USE [yumilk];
GO

-- 1. Xóa các bảng con phụ thuộc vào orders trước để tránh lỗi Msg 3726
IF OBJECT_ID('dbo.order_details', 'U') IS NOT NULL DROP TABLE dbo.order_details;
IF OBJECT_ID('dbo.order_logs', 'U') IS NOT NULL DROP TABLE dbo.order_logs;
IF OBJECT_ID('dbo.product_reviews', 'U') IS NOT NULL DROP TABLE dbo.product_reviews;

-- 2. Bây giờ mới có thể xóa bảng orders
IF OBJECT_ID('dbo.orders', 'U') IS NOT NULL DROP TABLE dbo.orders;
GO

-- 3. Tạo bảng orders với cấu trúc chuẩn hóa hoàn toàn (khớp với lệnh INSERT của bạn)
CREATE TABLE orders
(
    Id              uniqueidentifier                                    NOT NULL
        constraint PK_orders primary key,
    customer_id     uniqueidentifier
        constraint FK_orders_customers_customer_id references customers,
    total_price     int                                                 NOT NULL,
    shipping_fee    int                                                 NOT NULL,
    total_amount    int                                                 NOT NULL,
    address         nvarchar(2000)                                      NOT NULL,
    phone_number    nvarchar(20)                                        NOT NULL,
    note            nvarchar(max),
    status_id       int               default 0                         NOT NULL
        constraint FK_orders_order_statuses_status_id references order_statuses on delete cascade,
    created_at      datetime2         default getdate()                 NOT NULL,
    deleted_at      datetime2,
    payment_date    datetime2,
    payment_method  varchar(255),
    modified_at     datetime2,
    -- Phải dùng transaction_code để khớp với cột trong lệnh INSERT
    transaction_code bigint, 
    receiver_name   nvarchar(255)     default N''                       NOT NULL,
    district_id     int               default 0                         NOT NULL,
    ward_code       nvarchar(255)                                       NOT NULL,
    total_gram      int               default 0                         NOT NULL,
    shipping_code   nvarchar(255),
    email           nvarchar(255),
    is_preorder     bit               default 0                         NOT NULL,
    point_amount    int               default 0                         NOT NULL,
    voucher_amount  int               default 0                         NOT NULL,
    -- Thêm cột version kiểu varbinary(8) để nhận dữ liệu Hex (0x000...)
    version         varbinary(8) 
)
GO

